def _encode_with_positions(
    self, text: str, allowed_special: AbstractSet[str]
) -> tuple[list[int], list[int]]:
    """Encodes text into tokens, tracking the starting character position of each token."""
    if allowed_special:
        chunks = []
        last_end = 0
        for match in _special_token_regex(frozenset(allowed_special)).finditer(text):
            if match.start() > last_end:
                chunks.append((text[last_end : match.start()], last_end, False))
            chunks.append((match.group(), match.start(), True))
            last_end = match.end()
        if last_end < len(text):
            chunks.append((text[last_end:], last_end, False))
    else:
        chunks = [(text, 0, False)]

    tokens: list[int] = []
    positions: list[int] = []
    ordinary_pat = regex.compile(self._pat_str)

    for chunk, chunk_start, is_special in chunks:
        if is_special:
            tokens.append(self._core_bpe.encode_single_token(chunk.encode("utf-8")))
            positions.append(chunk_start)
            continue

        for piece_match in ordinary_pat.finditer(chunk):
            piece = piece_match.group()
            piece_start = chunk_start + piece_match.start()
            piece_tokens = self._core_bpe.encode_single_piece(piece.encode("utf-8"))

            char_offset = 0
            for token in piece_tokens:
                token_bytes = self._core_bpe.decode_single_token_bytes(token)
                start_offset = char_offset - (0x80 <= token_bytes[0] < 0xC0)
                positions.append(piece_start + max(0, start_offset))
                char_offset += sum(1 for b in token_bytes if not 0x80 <= b < 0xC0)
            tokens.extend(piece_tokens)

    return tokens, positions

